13	namespace MudBlazor
14	{
15	    /// <summary>
16	    /// A field for numeric values from users. 
17	    /// </summary>
18	    /// <typeparam name="T">The type of number being collected.</typeparam>
19	    public partial class MudNumericField<T> : MudDebouncedInput<T>
20	    {
21	        private T? _step;
22	        private T? _max;
23	        private T? _min;
24	        private readonly T? _minDefault;
25	        private readonly T? _maxDefault;
26	        private readonly T? _stepDefault;
27	        private bool _maxHasValue = false;
28	        private bool _minHasValue = false;
29	        private bool _stepHasValue = false;
30	        private MudInput<string> _elementReference = null!;
31	        private readonly string _elementId = Identifier.Create("numericField");
32	
33	        private readonly Comparer<T> _comparer = Comparer<T>.Default;
34	
35	        [Inject]
36	        private IKeyInterceptorService KeyInterceptorService { get; set; } = null!;
37	
38	        public MudNumericField()
39	        {
40	            Validation = new Func<T, Task<bool>>(ValidateInput);
41	            #region parameters default depending on T
42	
43	            //sbyte
44	            if (typeof(T) == typeof(sbyte) || typeof(T) == typeof(sbyte?))
45	            {
46	                _minDefault = (T)(object)sbyte.MinValue;
47	                _maxDefault = (T)(object)sbyte.MaxValue;
48	                _stepDefault = (T)(object)(sbyte)1;
49	            }
50	            // byte
51	            else if (typeof(T) == typeof(byte) || typeof(T) == typeof(byte?))
52	            {
53	                _minDefault = (T)(object)byte.MinValue;
54	                _maxDefault = (T)(object)byte.MaxValue;
55	                _stepDefault = (T)(object)(byte)1;
56	            }
57	            // short
58	            else if (typeof(T) == typeof(short) || typeof(T) == typeof(short?))
59	            {
60	                _minDefault = (T)(object)short.MinValue;
61	                _maxDefault = (T)(object)short.MaxValue;
62	                _stepDefault = (T)(object)(short)1;
63	            }
64	            // ushort
65	            else if (typeof(T) == typeof(ushort) || typeof(T) == typeof(ushort?))
66	            {
67	                _minDefault = (T)(object)ushort.MinValue;
68	                _maxDefault = (T)(object)ushort.MaxValue;
69	                _stepDefault = (T)(object)(ushort)1;
70	            }
71	            // int
72	            else if (typeof(T) == typeof(int) || typeof(T) == typeof(int?))
73	            {
74	                _minDefault = (T)(object)int.MinValue;
75	                _maxDefault = (T)(object)int.MaxValue;
76	                _stepDefault = (T)(object)1;
77	            }
78	            // uint
79	            else if (typeof(T) == typeof(uint) || typeof(T) == typeof(uint?))
80	            {
81	                _minDefault = (T)(object)uint.MinValue;
82	                _maxDefault = (T)(object)uint.MaxValue;
83	                _stepDefault = (T)(object)1u;
84	            }
85	            // long
86	            else if (typeof(T) == typeof(long) || typeof(T) == typeof(long?))
87	            {
88	                _minDefault = (T)(object)long.MinValue;
89	                _maxDefault = (T)(object)long.MaxValue;
90	                _stepDefault = (T)(object)1L;
91	            }
92	            // ulong
93	            else if (typeof(T) == typeof(ulong) || typeof(T) == typeof(ulong?))
94	            {
95	                _minDefault = (T)(object)ulong.MinValue;
96	                _maxDefault = (T)(object)ulong.MaxValue;
97	                _stepDefault = (T)(object)1ul;
98	            }
99	            // float
100	            else if (typeof(T) == typeof(float) || typeof(T) == typeof(float?))
101	            {
102	                _minDefault = (T)(object)float.MinValue;
103	                _maxDefault = (T)(object)float.MaxValue;
104	                _stepDefault = (T)(object)1.0f;
105	                InputMode = InputMode.@decimal;
106	            }
107	            // double
108	            else if (typeof(T) == typeof(double) || typeof(T) == typeof(double?))
109	            {
110	                _minDefault = (T)(object)double.MinValue;
111	                _maxDefault = (T)(object)double.MaxValue;
112	                _stepDefault = (T)(object)1.0;
113	                InputMode = InputMode.@decimal;
114	            }
115	            // decimal
116	            else if (typeof(T) == typeof(decimal) || typeof(T) == typeof(decimal?))
117	            {
118	                _minDefault = (T)(object)decimal.MinValue;
119	                _maxDefault = (T)(object)decimal.MaxValue;
120	                _stepDefault = (T)(object)1M;
121	                InputMode = InputMode.@decimal;
122	            }
123	
124	            #endregion parameters default depending on T
125	        }
