        [Test]
        public async Task Autocomplete_Should_Invoke_OnDebounceIntervalElapsed()
        {
            var comp = Context.Render<MudAutocomplete<string>>(parameters => parameters
                .Add(x => x.DebounceInterval, 100)
                .Add(x => x.SearchFunc, new Func<string, CancellationToken, Task<IEnumerable<string>>>((s, _) =>
                    Task.FromResult<IEnumerable<string>>(["Alabama", "Alaska", "Arizona"]))));

            var elapsedInvoked = false;
            string? elapsedText = null;

            await comp.SetParametersAndRenderAsync(parameters => parameters
                .Add(x => x.OnDebounceIntervalElapsed, new EventCallback<string>(null, new Action<string>(text =>
                {
                    elapsedInvoked = true;
                    elapsedText = text;
                }))));

            var input = comp.Find("input");
            await input.InputAsync("Al");

            // Wait for the debounce interval to elapse
            await Task.Delay(200);

            elapsedInvoked.Should().BeTrue("OnDebounceIntervalElapsed should have been called");
            elapsedText.Should().Be("Al");
        }
    }

